            ContentJson = """{"appRoute":"/employees","startButtonLabel":"Tour Employees","steps":[{"element":"[data-testid='employees-invite-btn']","popover":{"title":"Invite an Employee","description":"You don't add employees here. Click Invite Employee to jump to Admin > Users, where new accounts are set up. Only Admins see this button.","side":"bottom"}},{"element":".filters-bar","popover":{"title":"Search and Filter","description":"Narrow the list from here. Search by name, email, or phone. Filter by role, or by status — Active, Inactive, or All. The list below updates as you go.","side":"bottom"}},{"element":"app-data-table[tableId='employees-list']","popover":{"title":"The Employee List","description":"Every employee is listed here with their name, role, team, job title, email, phone, status, and start date. Click a column heading to sort. Click any row to open that person.","side":"top"}},{"element":".employee-name-cell","popover":{"title":"Open a Profile","description":"Click a name to open that person's profile. The top of the profile shows their name, role, and whether they're active, plus quick email and phone links. A back link brings you here again.","side":"bottom"}},{"element":"app-data-table[tableId='employees-list']","popover":{"title":"The Roster","description":"This list is your starting point. Search and filter to find someone, then click their row. Each row shows a quick summary, and a dash means that detail was left blank.","side":"top"}},{"element":".filters-bar","popover":{"title":"Profile Tabs","description":"Open an employee to see their profile tabs. Ten tabs cover their overview, time, pay, training, compliance, jobs, events, expenses, documents, and activity. Start on Overview for their details and contact info.","side":"bottom"}},{"element":"app-page-header","popover":{"title":"Back to the List","description":"This page is your home base. From anyone's profile, a back link returns you here, where you can pick another person or change your search and filters.","side":"bottom"}}]}"""
