        // ── Advanced Reference (Reference) ───────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Employees / HR — Advanced Reference",
            Slug = "employees-reference",
            Summary = "Edge-case and power-user notes for Employees / HR: the wired-but-unsurfaced department filter and the shared DataTable power features behind the roster.",
            ContentType = TrainingContentType.Reference,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 90,
            AppRoutes = """["/employees"]""",
            Tags = """["employees","reference","advanced"]""",
            ContentJson = """{"body":"## Filtering the List by Department (Built, Not Shown Yet)\n\nThe employee list supports a fourth filter — by **department** — that works end to end but isn't shown on screen yet. It's built and ready; this note records that it exists so admins know.\n\n- **What's there.** The search behind the list can already narrow people by department, matching against the department on each person's Overview tab.\n- **Why you don't see it.** The filter bar shows only three controls today — Search, Role, and Status. There's no department box for you to type in, so even though the search supports it, there's no way to set it from this screen right now.\n- **What it means for you.** Department still shows per person on the Overview tab (under Employment Details), and it's an optional field. To narrow by department today, combine the Role and Status filters with the list's own column filtering (below), or search by name.\n- **What's left.** Adding the department box to the filter bar is a small change; the work behind it is already done.\n\n## Power Features in the List\n\nThe employee list uses the same shared list control as the rest of the app, so it comes with every power feature that control offers. These aren't specific to Employees — you'll find the same tools on Parts, Leads, Inventory, and other lists.\n\n- **Sorting.** Click a column heading to sort by it. Hold **Shift** and click a second heading to sort by more than one column at once. Every column can be sorted: Name, Role, Team, Job Title, Email, Phone, Status, and Start Date.\n- **Filtering by column.** Columns you can filter show a small filter popup suited to the column — text, number, date, or a pick-from-list. On this list, Role is a pick-from-list drawn from your organization's roles. This works alongside the filter bar at the top, not instead of it.\n- **Managing columns.** The gear icon lets you show or hide columns, drag them into a new order, resize them, and reset everything back to the defaults.\n- **Right-click a heading.** Right-clicking a column heading opens a menu to sort, clear the sort, filter, clear filters, hide the column, or reset its width.\n- **Paging.** Choose 25, 50, or 100 rows per page. The counter at the top shows the total number of people.\n- **Your layout is remembered.** Your sorting, filters, and column choices are saved for you and restored next time you log in — even from another device.\n- **Nothing to show.** When no one matches, the list shows a friendly \"No employees\" message instead of a blank grid.\n- **Clicking a row.** Click any row to open that person's profile. Each row shows the name (Last, First), the Active or Inactive label, and a dash where an optional field (Team, Job Title, or Phone) is blank.\n","sections":[]}"""
        });

        Log.Information("Seeded Employees training modules");
